using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut = new();

    #region CreateOrder — Happy Path

    [TestMethod]
    public void CreateOrder_ValidSingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(20.00m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfAllItemTotals()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 3 },
            new() { ProductName = "Gadget", Price = 12.50m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert — 5*3 + 12.50*2 = 40.00
        Assert.AreEqual(40.00m, order.Total);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsDistinctIds()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = 1m, Quantity = 1 }
        };

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    #endregion

    #region CreateOrder — Edge / Error Cases

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "X", Price = 1m, Quantity = 1 }
        };

        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    [TestMethod]
    public void CreateOrder_ZeroQuantityItem_ReturnsZeroTotal()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Free", Price = 99.99m, Quantity = 0 }
        };

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(0m, order.Total);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = 7m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-1", items);

        var found = _sut.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsOnlyTheirOrders()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 1m, Quantity = 1 }
        };

        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-B", items);

        var result = _sut.GetOrdersByCustomer("cust-A");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        var result = _sut.GetOrdersByCustomer("nobody");

        Assert.AreEqual(0, result.Count);
    }

    #endregion
}

